mapper.select:
SELECT ( SELECT COUNT(DISTINCT cls.USER_ID) FROM COURSE_LEARNING_STATUS cls JOIN USERS u ON u.USER_ID = cls.USER_ID JOIN COURSE c ON c.COURSE_ID = cls.COURSE_ID WHERE cls.STATUS = 'IN_PROGRESS' AND cls.UPDATED_AT >= #{startDate} AND cls.UPDATED_AT < #{endDate} + 1
) AS activeLearners, ( SELECT COUNT(DISTINCT u.USER_ID) FROM USERS u WHERE 1 = 1
) AS totalLearners, ( SELECT NVL(ROUND(COUNT(CASE WHEN cls.STATUS = 'COMPLETED' THEN 1 END) / NULLIF(COUNT(*), 0) * 100, 1), 0) FROM COURSE_LEARNING_STATUS cls JOIN USERS u ON u.USER_ID = cls.USER_ID JOIN COURSE c ON c.COURSE_ID = cls.COURSE_ID WHERE cls.STATUS != 'CANCELED' AND cls.UPDATED_AT >= #{startDate} AND cls.UPDATED_AT < #{endDate} + 1
) AS completionRate, ( SELECT NVL(ROUND(AVG(cls.PROGRESS_RATE), 1), 0) FROM COURSE_LEARNING_STATUS cls JOIN USERS u ON u.USER_ID = cls.USER_ID JOIN COURSE c ON c.COURSE_ID = cls.COURSE_ID WHERE cls.STATUS != 'CANCELED' AND cls.UPDATED_AT >= #{startDate} AND cls.UPDATED_AT < #{endDate} + 1
) AS averageProgressRate, ( SELECT NVL(ROUND(COUNT(CASE WHEN qaa.CORRECT_YN = 'Y' THEN 1 END) / NULLIF(COUNT(*), 0) * 100, 1), 0) FROM QUIZ_ATTEMPT qa JOIN QUIZ_ATTEMPT_ANSWER qaa ON qaa.ATTEMPT_ID = qa.ATTEMPT_ID JOIN USERS u ON u.USER_ID = qa.USER_ID JOIN COURSE c ON c.COURSE_ID = qa.COURSE_ID WHERE qa.SUBMITTED_AT >= #{startDate} AND qa.SUBMITTED_AT < #{endDate} + 1
) AS quizCorrectRate FROM DUAL

WITH total_users AS ( SELECT COUNT(DISTINCT u.USER_ID) AS total_count FROM USERS u WHERE 1 = 1
), funnel_counts AS ( SELECT 1 AS sort_order, '신청' AS label, COUNT(DISTINCT ca.USER_ID) AS participant_count FROM COURSE_APPLICATION ca JOIN USERS u ON u.USER_ID = ca.USER_ID JOIN COURSE c ON c.COURSE_ID = ca.COURSE_ID WHERE ca.APPLICATION_STATUS IN ('WAITING', 'APPROVED') AND ca.APPLIED_AT >= #{startDate} AND ca.APPLIED_AT < #{endDate} + 1
UNION ALL SELECT 2 AS sort_order, '학습 시작' AS label, COUNT(DISTINCT cls.USER_ID) AS participant_count FROM COURSE_LEARNING_STATUS cls JOIN USERS u ON u.USER_ID = cls.USER_ID JOIN COURSE c ON c.COURSE_ID = cls.COURSE_ID WHERE cls.STATUS != 'CANCELED' AND cls.UPDATED_AT >= #{startDate} AND cls.UPDATED_AT < #{endDate} + 1
UNION ALL SELECT 3 AS sort_order, '수료' AS label, COUNT(DISTINCT cls.USER_ID) AS participant_count FROM COURSE_LEARNING_STATUS cls JOIN USERS u ON u.USER_ID = cls.USER_ID JOIN COURSE c ON c.COURSE_ID = cls.COURSE_ID WHERE cls.STATUS = 'COMPLETED' AND cls.UPDATED_AT >= #{startDate} AND cls.UPDATED_AT < #{endDate} + 1
) SELECT fc.label, NVL(ROUND(fc.participant_count / NULLIF(tu.total_count, 0) * 100, 1), 0) AS value FROM funnel_counts fc CROSS JOIN total_users tu ORDER BY fc.sort_order
